// Obtener fecha y hora actuales en Madrid
const now = new Date();
const madridNow = new Date(now.toLocaleString("en-US", { timeZone: "Europe/Madrid" }));

// Leer inputs que vienen de Retell vía el nodo anterior
const fechaInput = $input.first().json.body?.args?.Fecha || "";
const horaInput = $input.first().json.body?.args?.Hora || "";

// Mapa de días de la semana en español
const diasSemana = {
  "lunes": 1, "martes": 2, "miércoles": 3, "miercoles": 3,
  "jueves": 4, "viernes": 5, "sábado": 6, "sabado": 6, "domingo": 0
};

// Meses en español
const meses = {
  "enero": 0, "febrero": 1, "marzo": 2, "abril": 3,
  "mayo": 4, "junio": 5, "julio": 6, "agosto": 7,
  "septiembre": 8, "octubre": 9, "noviembre": 10, "diciembre": 11
};

// Resolver fecha
let fechaResuelta = new Date(madridNow);

const fechaLower = fechaInput.toLowerCase().trim();

if (fechaLower === "hoy") {
  // ya es madridNow
} else if (fechaLower === "mañana" || fechaLower === "manana") {
  fechaResuelta.setDate(fechaResuelta.getDate() + 1);
} else if (fechaLower === "pasado mañana" || fechaLower === "pasado manana") {
  fechaResuelta.setDate(fechaResuelta.getDate() + 2);
} else if (diasSemana[fechaLower] !== undefined) {
  // "este viernes", "el martes", etc.
  const diaObjetivo = diasSemana[fechaLower];
  const diaActual = fechaResuelta.getDay();
  let diff = diaObjetivo - diaActual;
  if (diff <= 0) diff += 7;
  fechaResuelta.setDate(fechaResuelta.getDate() + diff);
} else {
  // Intentar parsear fecha directa tipo "15 de marzo" o "2025-12-01"
  const matchDiaMes = fechaLower.match(/(\d{1,2})\s+de\s+(\w+)/);
  if (matchDiaMes) {
    const dia = parseInt(matchDiaMes[1]);
    const mes = meses[matchDiaMes[2]];
    if (mes !== undefined) {
      fechaResuelta.setDate(dia);
      fechaResuelta.setMonth(mes);
      if (fechaResuelta < madridNow) {
        fechaResuelta.setFullYear(fechaResuelta.getFullYear() + 1);
      }
    }
  } else {
    // Formato YYYY-MM-DD directo
    const directa = new Date(fechaInput);
    if (!isNaN(directa)) fechaResuelta = directa;
  }
}

// Resolver hora
let horaFinal = "10:00";
const horaLower = horaInput.toLowerCase().trim();

const horasNaturales = {
  "mediodía": "12:00", "mediodia": "12:00",
  "medianoche": "00:00",
};

if (horasNaturales[horaLower]) {
  horaFinal = horasNaturales[horaLower];
} else {
  // Detectar "cinco y media de la tarde" → 17:30
  const matchHora = horaLower.match(/(\w+)(?:\s+y\s+(media|cuarto))?\s+de\s+la\s+(mañana|manana|tarde|noche)/);
  if (matchHora) {
    const numerosEsp = {
      "una":1,"dos":2,"tres":3,"cuatro":4,"cinco":5,"seis":6,
      "siete":7,"ocho":8,"nueve":9,"diez":10,"once":11,"doce":12
    };
    let h = numerosEsp[matchHora[1]] || 12;
    let m = matchHora[2] === "media" ? 30 : matchHora[2] === "cuarto" ? 15 : 0;
    const periodo = matchHora[3];
    if ((periodo === "tarde" || periodo === "noche") && h < 12) h += 12;
    if (periodo === "mañana" && h === 12) h = 0;
    horaFinal = `${String(h).padStart(2,"0")}:${String(m).padStart(2,"0")}`;
  } else {
    // Formato directo HH:MM
    const matchDirecto = horaLower.match(/(\d{1,2}):(\d{2})/);
    if (matchDirecto) {
      horaFinal = `${String(matchDirecto[1]).padStart(2,"0")}:${matchDirecto[2]}`;
    }
  }
}

// Construir fecha ISO 8601 con zona horaria Madrid (+01:00 o +02:00)
const año = fechaResuelta.getFullYear();
const mes = String(fechaResuelta.getMonth() + 1).padStart(2, "0");
const dia = String(fechaResuelta.getDate()).padStart(2, "0");
const [hh, mm] = horaFinal.split(":");

// Detectar si España está en horario de verano
const janOffset = new Date(año, 0, 1).getTimezoneOffset();
const julOffset = new Date(año, 6, 1).getTimezoneOffset();
const estaEnVerano = fechaResuelta.getTimezoneOffset() < Math.max(janOffset, julOffset);
const offset = estaEnVerano ? "+02:00" : "+01:00";

const fechaISO = `${año}-${mes}-${dia}T${hh}:${mm}:00${offset}`;

return [{ json: { fechaISO, fecha: `${año}-${mes}-${dia}`, hora: `${hh}:${mm}` } }];
```

